import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, Marker, Popup } from "react-leaflet";
import L from "leaflet";
import axios from "./api";
import Alerts from "./Alerts";
import "leaflet/dist/leaflet.css";
import "./busmap.css";

// Custom icons
const ghostIcon = new L.Icon({
  iconUrl: "/red-bus.png",
  iconSize: [25, 25],
  iconAnchor: [12, 12],
  popupAnchor: [0, -12],
});

const normalIcon = new L.Icon({
  iconUrl: "/green-bus.png",
  iconSize: [25, 25],
  iconAnchor: [12, 12],
  popupAnchor: [0, -12],
});

export default function BusMap() {
  const [buses, setBuses] = useState([]);
  const [alerts, setAlerts] = useState([]);

  const fetchBuses = async () => {
    try {
      const response = await axios.get("/buses");
      const data = response.data;

      // Detect unusual activity (ghost buses)
      const newAlerts = [];
      data.forEach((bus) => {
        if (bus.status === "ghost") {
          newAlerts.push(`Ghost bus detected: ${bus.id} in ${bus.borough}`);
        }
      });

      setAlerts(newAlerts);
      setBuses(data);
    } catch (error) {
      console.error("Error fetching bus data:", error);
    }
  };

  useEffect(() => {
    fetchBuses();
    const interval = setInterval(fetchBuses, 120000); // 2 min refresh
    return () => clearInterval(interval);
  }, []);

  return (
    <div>
      <Alerts alerts={alerts} />
      <MapContainer
        center={[40.7128, -74.006]}
        zoom={11}
        style={{ height: "600px", width: "100%" }}
      >
        <TileLayer
          url="https://tiles.stadiamaps.com/tiles/alidade_smooth/{z}/{x}/{y}{r}.png"
          attribution='&copy; <a href="https://stadiamaps.com/">Stadia Maps</a>'
        />
        {buses.map((bus) => (
          <Marker
            key={bus.id}
            position={[bus.lat, bus.lon]}
            icon={bus.status === "ghost" ? ghostIcon : normalIcon}
          >
            <Popup>
              Bus ID: {bus.id} <br />
              Status: {bus.status} <br />
              Borough: {bus.borough}
            </Popup>
          </Marker>
        ))}
      </MapContainer>
    </div>
  );
}
